  ('optometrist-moex-00874', 'optometrist', 'optometrist-moex-111-c33a0f9f', 'sub-optometrist-03', NULL, 'single_choice', '在近點聚合（nearpointofconvergence,NPC）的檢查，若調節性視標與筆燈或筆燈附加紅色濾鏡片的檢查 結果不同時，個案可能有下列何種情況？', '["調節過度", "調節不足", "聚合過度", "聚合不足"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:44+00:00", "source_pdf_sha1": "87ef5245a224", "answer_pdf_sha1": "ba5822650940", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "111", "s": "1003", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視光學", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00875', 'optometrist', 'optometrist-moex-111-c33a0f9f', 'sub-optometrist-03', NULL, 'single_choice', '相對性瞳孔傳入障礙（relativeafferentpupillarydefect,RAPD）應該是在瞳孔光反射檢查的那個步驟發現的？', '["直接反應（directresponse）", "間接反應（consensualresponse）", "筆燈搖擺測試（swingingflashlighttest）", "瞳孔調節反應（accommodativeresponseofpupil）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:44+00:00", "source_pdf_sha1": "87ef5245a224", "answer_pdf_sha1": "ba5822650940", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "111", "s": "1003", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視光學", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00876', 'optometrist', 'optometrist-moex-111-c33a0f9f', 'sub-optometrist-03', NULL, 'single_choice', '有關利用Park’s三步驟（Park’s3-step）檢查那一條眼外肌麻痺的敘述，下列何者錯誤？', '["首先決定那一眼是上偏位眼（hyperdeviatedeye）", "直視前方，頭部傾斜向左邊或傾斜向右邊測試偏位", "移動筆燈注視燈光，頭部傾斜向左邊或傾斜向右邊測試偏位", "移動筆燈注視燈光，指示患者頭部不要轉動，向右看或向左看測試偏位"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:44+00:00", "source_pdf_sha1": "87ef5245a224", "answer_pdf_sha1": "ba5822650940", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "111", "s": "1003", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視光學", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00877', 'optometrist', 'optometrist-moex-111-c33a0f9f', 'sub-optometrist-03', NULL, 'single_choice', '有關眼軸眼位相關檢查，下列敘述何者正確？', '["進行赫希柏格檢查（Hirschbergtest）觀察視網膜的反光點", "遮蓋-去遮蓋檢查（cover-uncovertest）用來確定有無隱斜位或斜視", "用直接眼底鏡照射眼睛，觀察眼底反射光的檢查稱為科林斯基檢查（Krimskytest）", "布魯克諾檢查（Brücknertest）中，較黑較暗的紅反射眼可能有斜視、介質不透明等問題"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:44+00:00", "source_pdf_sha1": "87ef5245a224", "answer_pdf_sha1": "ba5822650940", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "111", "s": "1003", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視光學", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00878', 'optometrist', 'optometrist-moex-111-c33a0f9f', 'sub-optometrist-03', NULL, 'single_choice', '有關眼初檢之期望值的敘述，下列何者錯誤？', '["成年人立體視為20秒角", "近點內聚力破裂點3-5cm，回復點5-7cm", "眼外肌運動檢查平順、準確、廣泛", "近距離遮蓋檢查3個稜鏡內隱斜位"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:44+00:00", "source_pdf_sha1": "87ef5245a224", "answer_pdf_sha1": "ba5822650940", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "111", "s": "1003", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視光學", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00879', 'optometrist', 'optometrist-moex-111-c33a0f9f', 'sub-optometrist-03', NULL, 'single_choice', '有關遮蓋檢查中的紀錄，CTcc：15ΔRET;8ΔEP''，下列敘述何者正確？', '["受測者矯正後，遠距離有15個稜鏡度右眼內斜視；近距離有8個稜鏡度內隱斜位", "受測者矯正後，遠距離有15個稜鏡度右眼外斜視；近距離有8個稜鏡度外隱斜位", "受測者矯正後，遠距離有15個稜鏡度右眼內隱斜位；近距離有8個稜鏡度內斜視", "受測者矯正後，遠距離有15個稜鏡度右眼外隱斜位；近距離有8個稜鏡度外斜視"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:44+00:00", "source_pdf_sha1": "87ef5245a224", "answer_pdf_sha1": "ba5822650940", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "111", "s": "1003", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視光學", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00880', 'optometrist', 'optometrist-moex-111-c33a0f9f', 'sub-optometrist-03', NULL, 'single_choice', '關於靜態視網膜檢影鏡法（staticretinoscopy），下列何者錯誤？', '["透過平光鏡看到逆動（againstmotion），代表病人可能有近視", "透過平光鏡看到逆動，需要用凹透鏡來達到中和（neutralization）", "如果反射光條（streak）出現偏斜現象（skewphenomenon），表示可能有散光（astigmatism）", "通常逆動到中和點比順動（withmotion）到中和點較容易觀察"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:44+00:00", "source_pdf_sha1": "87ef5245a224", "answer_pdf_sha1": "ba5822650940", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "111", "s": "1003", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視光學", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00881', 'optometrist', 'optometrist-moex-111-c33a0f9f', 'sub-optometrist-03', NULL, 'single_choice', '下列何項敘述最能表示「散光」？', '["因視網膜有病變，使患者看到閃爍的光線，影響視力", "光線經過眼睛構造後，發散而使光線無法聚焦，造成視力模糊", "光線經過眼睛構造後，由於中心及周邊的折射力不同，使光線無法聚焦在同一點，造成視力模糊", "光線進入之眼睛，經過角膜或水晶體，由於不同方位的折射力不同，無法聚焦在同一點，而引起視力模糊"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:44+00:00", "source_pdf_sha1": "87ef5245a224", "answer_pdf_sha1": "ba5822650940", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "111", "s": "1003", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視光學", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00882', 'optometrist', 'optometrist-moex-111-c33a0f9f', 'sub-optometrist-03', NULL, 'single_choice', '有關電腦驗光機的敘述，下列何者錯誤？', '["不合作的幼童或病患，無法配合做檢查，可能會需要使用視網膜鏡檢查", "在高度數病患準確性較高，低度數病人準確性較低", "有些病患在電腦驗光機前無法讓眼睛放鬆到遠點，導致過度調節而產生很嚴重的假性近視且不自覺", "測量時，只能選擇測量視軸的中央區"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:44+00:00", "source_pdf_sha1": "87ef5245a224", "answer_pdf_sha1": "ba5822650940", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "111", "s": "1003", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視光學", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
